#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[1005]; scanf("%s", S);
        int cnt0=0; for(int i=0;i<N;i++) if(S[i]=='0') cnt0++;
        // build target on the fly
        int *mism = (int*)malloc(N*sizeof(int));
        int m=0;
        for(int i=0;i<N;i++){
            char target = (i<cnt0)?'0':'1';
            if(S[i]!=target) mism[m++] = i;
        }
        int K = m/2;
        printf("%d\n", K);
        for(int l=0, r=m-1; l<r; l++, r--){
            int start = mism[l]+1; // 1‑based
            int len = mism[r]-mism[l]+1;
            printf("%d %d\n", start, len);
        }
        free(mism);
    }
    return 0;
}

