using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        string S; cin>>S;
        int cnt0 = count(S.begin(), S.end(), '0');
        vector<int> mism;
        for(int i=0;i<N;i++){
            char target = (i<cnt0)?'0':'1';
            if(S[i]!=target) mism.push_back(i);
        }
        int K = mism.size()/2;
        cout<<K<<"\n";
        for(size_t l=0, r=mism.size()?mism.size()-1:0; l<r; ++l, --r){
            int start = mism[l]+1; // 1‑based
            int len = mism[r]-mism[l]+1;
            cout<<start<<' '<<len<<"\n";
        }
    }
    return 0;
}

