import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            int cnt0 = 0;
            for (int i = 0; i < N; i++) if (S.charAt(i) == '0') cnt0++;
            List<Integer> mism = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                char target = (i < cnt0) ? '0' : '1';
                if (S.charAt(i) != target) mism.add(i);
            }
            int K = mism.size() / 2;
            out.append(K).append('\n');
            for (int l = 0, r = mism.size() - 1; l < r; l++, r--) {
                int start = mism.get(l) + 1; // 1‑based
                int len = mism.get(r) - mism.get(l) + 1;
                out.append(start).append(' ').append(len).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

