const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const S = input[idx++];
  let cnt0 = 0;
  for (let ch of S) if (ch === '0') cnt0++;
  let mism = [];
  for (let i = 0; i < N; i++) {
    const target = i < cnt0 ? '0' : '1';
    if (S[i] !== target) mism.push(i);
  }
  const K = mism.length >> 1;
  output.push(String(K));
  for (let l = 0, r = mism.length - 1; l < r; l++, r--) {
    const start = mism[l] + 1; // 1‑based
    const len = mism[r] - mism[l] + 1;
    output.push(start + ' ' + len);
  }
}
